import{_ as e,c as s,o as t,aj as i}from"./chunks/framework.VtnL2jmu.js";const g=JSON.parse('{"title":"HTTPie 安装全攻略","description":"","frontmatter":{},"headers":[],"relativePath":"Linux/HTTPie安装全攻略.md","filePath":"Linux/HTTPie安装全攻略.md"}'),n={name:"Linux/HTTPie安装全攻略.md"};function o(d,a,r,p,l,h){return t(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="httpie-安装全攻略" tabindex="-1">HTTPie 安装全攻略 <a class="header-anchor" href="#httpie-安装全攻略" aria-label="Permalink to “HTTPie 安装全攻略”">​</a></h1><blockquote><p>Linux 命令行开发神器</p></blockquote><h3 id="📝-为什么放弃-postman" tabindex="-1">📝 为什么放弃 Postman？ <a class="header-anchor" href="#📝-为什么放弃-postman" aria-label="Permalink to “📝 为什么放弃 Postman？”">​</a></h3><p>作为后端开发，频繁在 IDE 和 Postman 之间切换极其耗时。<strong>HTTPie</strong> 让你在终端就能以“类自然语言”的方式调试 Spring Boot 接口，语法高亮、自动 JSON 序列化，体验极佳。</p><hr><h3 id="🛠-安装篇-避开-包版本冲突-的大坑" tabindex="-1">🛠 安装篇：避开“包版本冲突”的大坑 <a class="header-anchor" href="#🛠-安装篇-避开-包版本冲突-的大坑" aria-label="Permalink to “🛠 安装篇：避开“包版本冲突”的大坑”">​</a></h3><h4 id="_1-为什么不建议直接-apt-install" tabindex="-1">1. 为什么不建议直接 <code>apt install</code>？ <a class="header-anchor" href="#_1-为什么不建议直接-apt-install" aria-label="Permalink to “1. 为什么不建议直接 apt install？”">​</a></h4><p>在 Ubuntu 等系统中，<code>apt</code> 安装的版本往往较旧，且容易与系统中已有的 <code>python-requests</code> 或 <code>urllib3</code>（通过 pip 安装的）发生版本冲突，导致 <code>ImportError</code> 报错。</p><h4 id="_2-最佳实践-使用-pipx-隔离安装" tabindex="-1">2. 最佳实践：使用 <code>pipx</code> 隔离安装 <a class="header-anchor" href="#_2-最佳实践-使用-pipx-隔离安装" aria-label="Permalink to “2. 最佳实践：使用 pipx 隔离安装”">​</a></h4><p><code>pipx</code> 会为每个工具创建独立虚拟环境，完美解决“包打架”问题。</p><p>Bash</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 1. 安装 pipx</span></span>
<span class="line"><span>sudo apt update</span></span>
<span class="line"><span>sudo apt install pipx</span></span>
<span class="line"><span>pipx ensurepath</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 2. 隔离安装 HTTPie</span></span>
<span class="line"><span>pipx install httpie</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 3. 激活环境（仅限第一次安装，或重启终端）</span></span>
<span class="line"><span>source ~/.bashrc</span></span>
<span class="line"><span># 如果是旧窗口，执行 hash -r 清除之前的路径缓存</span></span>
<span class="line"><span>hash -r</span></span></code></pre></div><hr><h3 id="💡-核心语法-5分钟上手" tabindex="-1">💡 核心语法：5分钟上手 <a class="header-anchor" href="#💡-核心语法-5分钟上手" aria-label="Permalink to “💡 核心语法：5分钟上手”">​</a></h3><p>HTTPie 的设计逻辑非常优雅，记住这四个符号：</p><table tabindex="0"><thead><tr><th><strong>符号</strong></th><th><strong>作用</strong></th><th><strong>示例</strong></th><th><strong>对应 JSON / URL</strong></th></tr></thead><tbody><tr><td><strong><code>:</code></strong></td><td>端口缩写</td><td><code>http :8080/get</code></td><td><code>http://localhost:8080/get</code></td></tr><tr><td><strong><code>=</code></strong></td><td>JSON 字符串</td><td><code>name=muzi</code></td><td><code>{&quot;name&quot;: &quot;muzi&quot;}</code></td></tr><tr><td><strong><code>:=</code></strong></td><td>JSON 非字符</td><td><code>age:=30</code></td><td><code>{&quot;age&quot;: 30}</code></td></tr><tr><td><strong><code>==</code></strong></td><td>Query 参数</td><td><code>id==1</code></td><td><code>?id=1</code></td></tr><tr><td><strong><code>@</code></strong></td><td>上传文件</td><td><code>file@./a.png</code></td><td>表单上传文件</td></tr></tbody></table><hr><h3 id="🏃‍♂️-实战场景-spring-boot-开发常用" tabindex="-1">🏃‍♂️ 实战场景（Spring Boot 开发常用） <a class="header-anchor" href="#🏃‍♂️-实战场景-spring-boot-开发常用" aria-label="Permalink to “🏃‍♂️ 实战场景（Spring Boot 开发常用）”">​</a></h3><h4 id="✅-场景一-测试登录接口-post-json" tabindex="-1">✅ 场景一：测试登录接口（POST JSON） <a class="header-anchor" href="#✅-场景一-测试登录接口-post-json" aria-label="Permalink to “✅ 场景一：测试登录接口（POST JSON）”">​</a></h4><p>Bash</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>http :8888/api/auth/login username=admin password=123456</span></span></code></pre></div><h4 id="✅-场景二-带-token-请求-headers" tabindex="-1">✅ 场景二：带 Token 请求（Headers） <a class="header-anchor" href="#✅-场景二-带-token-请求-headers" aria-label="Permalink to “✅ 场景二：带 Token 请求（Headers）”">​</a></h4><p>Bash</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>http :8888/api/user/info &quot;Authorization:Bearer YourTokenHere&quot;</span></span></code></pre></div><h4 id="✅-场景三-模拟带参数的搜索-get" tabindex="-1">✅ 场景三：模拟带参数的搜索（GET） <a class="header-anchor" href="#✅-场景三-模拟带参数的搜索-get" aria-label="Permalink to “✅ 场景三：模拟带参数的搜索（GET）”">​</a></h4><p>Bash</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>http :8888/api/books/search keyword==Java category==Backend</span></span></code></pre></div><hr><h3 id="⚠️-常见排错-遇到报错怎么办" tabindex="-1">⚠️ 常见排错：遇到报错怎么办？ <a class="header-anchor" href="#⚠️-常见排错-遇到报错怎么办" aria-label="Permalink to “⚠️ 常见排错：遇到报错怎么办？”">​</a></h3><ul><li><strong>问题</strong>：<code>-bash: /usr/bin/http: No such file or directory</code><ul><li><strong>原因</strong>：卸载旧版后，Bash 还记着旧路径。</li><li><strong>解决</strong>：执行 <code>hash -d http</code> 或 <code>hash -r</code> 重置缓存。</li></ul></li><li><strong>问题</strong>：<code>ImportError: cannot import name &#39;DEFAULT_CIPHERS&#39;</code><ul><li><strong>原因</strong>：典型的 <code>urllib3</code> 版本冲突。</li><li><strong>解决</strong>：卸载 <code>apt</code> 版，改用 <code>pipx</code> 安装。</li></ul></li></ul><hr><h3 id="🔧-提效小贴士" tabindex="-1">🔧 提效小贴士 <a class="header-anchor" href="#🔧-提效小贴士" aria-label="Permalink to “🔧 提效小贴士”">​</a></h3><p>在 <code>~/.bashrc</code> 中添加别名，让手感更丝滑：</p><p>Bash</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>alias h=&#39;http&#39;</span></span>
<span class="line"><span>alias hs=&#39;https&#39;</span></span></code></pre></div><p>现在，你只需要 <code>h :8888/api</code> 即可一键起飞！🚀</p><p>#Linux #SpringBoot #后端开发 #程序员日常 #HTTPie #效率工具</p>`,37)])])}const b=e(n,[["render",o]]);export{g as __pageData,b as default};
